commonMistakes.correctCode:
// If you need the value at creation time, capture it explicitly
function make() {
  let x = 1;
  const captured = x;  // Capture the current value
  const fn = function() { return captured; };
  x = 2;
  return fn;
}
console.log(make()()); // 1

